import React, { useState } from 'react';
import { Menu, X, User, ShoppingCart } from 'lucide-react';
import { Link } from 'react-router-dom'; // Using Link for semantic navigation

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);

  const toggleMenu = () => {
    setIsOpen(!isOpen);
  };

  return (
    <nav className="bg-zinc-900 text-white p-4 sticky top-0 z-50 shadow-lg">
      <div className="container mx-auto flex justify-between items-center">
        {/* Brand Name */}
        <Link to="/" className="text-2xl font-bold tracking-wider hover:text-zinc-300 transition-colors duration-300">
          Aura Atelier
        </Link>

        {/* Desktop Navigation */}
        <div className="hidden md:flex items-center space-x-8">
          <Link to="/shop" className="hover:text-zinc-300 transition-colors duration-300">Shop</Link>
          <Link to="/categories" className="hover:text-zinc-300 transition-colors duration-300">Categories</Link>
          <Link to="/contact" className="hover:text-zinc-300 transition-colors duration-300">Contact</Link>
          <div className="h-6 w-px bg-zinc-700"></div> {/* Separator */}
          <Link to="/account" className="relative p-2 rounded-full hover:bg-zinc-700 transition-colors duration-300">
            <User className="h-5 w-5" />
            <span className="sr-only">Account</span>
          </Link>
          <Link to="/cart" className="relative p-2 rounded-full hover:bg-zinc-700 transition-colors duration-300">
            <ShoppingCart className="h-5 w-5" />
            <span className="absolute -top-1 -right-1 bg-zinc-600 text-white text-xs rounded-full h-4 w-4 flex items-center justify-center">0</span>
            <span className="sr-only">Cart</span>
          </Link>
        </div>

        {/* Mobile Menu Button */}
        <div className="md:hidden flex items-center space-x-4">
          <Link to="/account" className="relative p-2 rounded-full hover:bg-zinc-700 transition-colors duration-300">
            <User className="h-5 w-5" />
            <span className="sr-only">Account</span>
          </Link>
          <Link to="/cart" className="relative p-2 rounded-full hover:bg-zinc-700 transition-colors duration-300">
            <ShoppingCart className="h-5 w-5" />
            <span className="absolute -top-1 -right-1 bg-zinc-600 text-white text-xs rounded-full h-4 w-4 flex items-center justify-center">0</span>
            <span className="sr-only">Cart</span>
          </Link>
          <button onClick={toggleMenu} className="p-2 rounded-md hover:bg-zinc-700 transition-colors duration-300">
            {isOpen ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
            <span className="sr-only">{isOpen ? 'Close menu' : 'Open menu'}</span>
          </button>
        </div>
      </div>

      {/* Mobile Navigation */}
      {isOpen && (
        <div className="md:hidden bg-zinc-800 py-4 mt-4 rounded-md">
          <div className="flex flex-col items-center space-y-4">
            <Link to="/shop" onClick={toggleMenu} className="block w-full text-center py-2 hover:bg-zinc-700 rounded-md transition-colors duration-300">Shop</Link>
            <Link to="/categories" onClick={toggleMenu} className="block w-full text-center py-2 hover:bg-zinc-700 rounded-md transition-colors duration-300">Categories</Link>
            <Link to="/contact" onClick={toggleMenu} className="block w-full text-center py-2 hover:bg-zinc-700 rounded-md transition-colors duration-300">Contact</Link>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

